// === Stage -> Meta-Event + Klienten-Config ===
// TODO: CLIENTS-Map durch echten Store-Lookup ersetzen (gemappt ueber body.locationId).
const body = $json.body || $json;
const CLIENTS = {
  "LOCATION_ID_BEISPIEL": { pixelId: "META_PIXEL_ID", capiToken: "META_CAPI_TOKEN" }
};
const cfg = CLIENTS[body.locationId] || CLIENTS["LOCATION_ID_BEISPIEL"];
const MAP = {
  "Termin gebucht":    { event: "Schedule" },
  "Termin erschienen": { event: "AppointmentShow" },
  "Kunde gewonnen":    { event: "Purchase", value: Number(body.value || 0) }
};
const m = MAP[body.stage];
if (!m) return []; // nicht getrackte Stage -> nichts senden
return [{ json: {
  pixelId: cfg.pixelId, capiToken: cfg.capiToken,
  event_name: m.event, event_id: body.event_id || "",
  value: m.value || 0, fbc: body.fbc || "", fbp: body.fbp || ""
}}];
